#include <bits/stdc++.h>
using namespace std;

void matchPairs(int n, char nuts[], char bolts[]) {
    vector<char> order = {'!', '#', '$', '%', '&', '*', '?', '@', '^'};

    int nutsIndex = 0, boltsIndex = 0;

    // Match according to the given order
    for(char c : order) {
        // Arrange nuts
        for(int j = 0; j < n; j++) {
            if(nuts[j] == c) {
                swap(nuts[j], nuts[nutsIndex]);
                nutsIndex++;
            }
        }

        // Arrange bolts
        for(int j = 0; j < n; j++) {
            if(bolts[j] == c) {
                swap(bolts[j], bolts[boltsIndex]);  // Fixed: swap with array element
                boltsIndex++;
            }
        }
    }
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        char nuts[n], bolts[n];
        for(int i = 0; i < n; i++) cin >> nuts[i];
        for(int i = 0; i < n; i++) cin >> bolts[i];

        matchPairs(n, nuts, bolts);

        for(int i = 0; i < n; i++) cout << nuts[i] << " ";
        cout << endl;
        for(int i = 0; i < n; i++) cout << bolts[i] << " ";
        cout << endl;
    }
    return 0;
}
